-- ============================================================
-- 8. PERMISOS POR ROL (producer y mvz_government nuevos tenants)
-- Reutilizamos los permission IDs del SeedActual.sql
-- ============================================================

-- Permisos para roles 'producer' (tenants 1-10)
SELECT tr.id, p.id
FROM public.tenant_roles tr
JOIN public.permissions p ON p.key = ANY(ARRAY[
  'producer.dashboard.read', 'producer.upp.read', 'producer.upp.write',
  'producer.bovinos.read', 'producer.bovinos.write',
  'producer.movements.read', 'producer.movements.write',
  'producer.exports.read', 'producer.exports.write',
  'producer.documents.read', 'producer.documents.write',
  'producer.notifications.read', 'producer.profile.read', 'producer.profile.write',
  'producer.employees.read', 'producer.employees.write'
])
WHERE tr.key = 'producer'
  AND tr.tenant_id IN (
    '10000000-0000-0000-0000-000000000001','10000000-0000-0000-0000-000000000002',
    '10000000-0000-0000-0000-000000000003','10000000-0000-0000-0000-000000000004',
    '10000000-0000-0000-0000-000000000005','10000000-0000-0000-0000-000000000006',
    '10000000-0000-0000-0000-000000000007','10000000-0000-0000-0000-000000000008',
    '10000000-0000-0000-0000-000000000009','10000000-0000-0000-0000-000000000010'
  )
ON CONFLICT (tenant_role_id, permission_id) DO NOTHING;

-- Permisos para roles 'mvz_government' (tenants MVZ 1-4)
SELECT tr.id, p.id
FROM public.tenant_roles tr
JOIN public.permissions p ON p.key = ANY(ARRAY[
  'mvz.dashboard.read', 'mvz.assignments.read', 'mvz.bovinos.read',
  'mvz.tests.read', 'mvz.tests.write', 'mvz.tests.sync',
  'mvz.quarantines.read', 'mvz.quarantines.write',
  'mvz.exports.read', 'mvz.exports.write', 'mvz.notifications.read'
])
WHERE tr.key = 'mvz_government'
  AND tr.tenant_id IN (
    '20000000-0000-0000-0000-000000000001','20000000-0000-0000-0000-000000000002',
    '20000000-0000-0000-0000-000000000003','20000000-0000-0000-0000-000000000004'
  )
ON CONFLICT (tenant_role_id, permission_id) DO NOTHING;


